+        if target == self.screen {
+            return false;
+        }
+        self.screen_history.push(self.screen);
+        self.screen = target;
+        true
+    }
+
+    /// Go back to the previous screen. Returns `true` if history was non-empty.
+    pub fn navigate_back(&mut self) -> bool {
